//! Spec-compliance tests: Tracked Change Accept/Reject Semantics
//!
//! These tests verify accept_all and reject_all against the OOXML spec
//! rules for tracked changes (ECMA-376 Part 1, Section 17.13.5).
//!
//!
//! Fixture DOCX files are generated by
//! `testdata/spec-compliance/tracked-change-accept-reject/create_docs.py`.

use std::fs;

use stemma::{
    Alignment, BlockNode, CanonDoc, DocxRuntime, InlineNode, SimpleRuntime, TrackingStatus,
    accept_all, reject_all_with_styles,
};

use crate::common;

const FIXTURES: &str = "testdata/spec-compliance/tracked-change-accept-reject";

/// Import a fixture and return its canonical model WITHOUT normalization.
///
/// Uses `import_docx().canonical` (which preserves pre-existing tracked changes)
/// instead of `view().canonical` (which normalizes them away via `normalize_if_needed`).
fn import_fixture(name: &str) -> (SimpleRuntime, CanonDoc) {
    let path = format!("{FIXTURES}/{name}/input.docx");
    let bytes = fs::read(&path).unwrap_or_else(|e| panic!("read {path}: {e}"));
    let runtime = SimpleRuntime::new();
    let import = runtime
        .import_docx(&bytes)
        .unwrap_or_else(|e| panic!("import {path}: {e:?}"));
    (runtime, std::sync::Arc::unwrap_or_clone(import.canonical))
}

/// Extract all text from a CanonDoc by concatenating paragraph text across all blocks.
fn all_text(doc: &CanonDoc) -> String {
    let paras = common::all_paragraphs(doc);
    paras
        .iter()
        .map(|p| common::paragraph_text(p))
        .collect::<Vec<_>>()
        .join(" ")
}

/// Count paragraphs at the top level (excluding table cells).
fn top_level_paragraph_count(doc: &CanonDoc) -> usize {
    doc.blocks
        .iter()
        .filter(|tb| matches!(&tb.block, BlockNode::Paragraph(_)))
        .count()
}

// ── Test 1: Accept deleted paragraph mark merges into following ──────────

/// ECMA-376 §17.13.5.15: When a paragraph mark is deleted and the deletion is
/// accepted, the paragraph's contents merge into the FOLLOWING paragraph. The
/// following paragraph's properties (pPr) should win.
///
/// Fixture: Two paragraphs. First is center-aligned with deleted para mark,
/// second is left-aligned.
///
/// After accept_all:
/// - Should produce ONE paragraph (merged)
/// - The surviving paragraph should have the SECOND paragraph's alignment (left)
///
/// Previously a known gap -- accept_all now correctly merges paragraphs
/// when a deleted paragraph mark is accepted.
#[test]
fn spec_accept_deleted_paragraph_mark_merges_into_following() {
    let (_runtime, doc) = import_fixture("para-mark-del-merge");

    // Verify fixture: should start with 2 paragraphs
    let initial_count = top_level_paragraph_count(&doc);
    assert_eq!(
        initial_count, 2,
        "fixture should have 2 paragraphs before accept, got {initial_count}"
    );

    // Verify the first paragraph has a deleted para mark
    let first_para = doc
        .blocks
        .iter()
        .find_map(|tb| match &tb.block {
            BlockNode::Paragraph(p) => Some(p),
            _ => None,
        })
        .expect("should have at least one paragraph");
    assert!(
        matches!(
            &first_para.para_mark_status,
            Some(TrackingStatus::Deleted(_))
        ),
        "first paragraph should have Deleted para_mark_status, got {:?}",
        first_para.para_mark_status
    );

    // Accept all tracked changes
    let mut accepted = doc.clone();
    accept_all(&mut accepted);

    // After accepting, paragraphs should merge into ONE
    let accepted_count = top_level_paragraph_count(&accepted);
    assert_eq!(
        accepted_count, 1,
        "accepting a deleted paragraph mark should merge two paragraphs into one, got {accepted_count}"
    );

    // The merged paragraph should contain text from both paragraphs
    let text = all_text(&accepted);
    assert!(
        text.contains("First paragraph text"),
        "merged paragraph should contain first paragraph's text, got: '{text}'"
    );
    assert!(
        text.contains("second paragraph text"),
        "merged paragraph should contain second paragraph's text, got: '{text}'"
    );

    // The surviving paragraph should have the SECOND paragraph's properties (left alignment)
    let merged_para = accepted
        .blocks
        .iter()
        .find_map(|tb| match &tb.block {
            BlockNode::Paragraph(p) => Some(p),
            _ => None,
        })
        .expect("should have the merged paragraph");
    assert_eq!(
        merged_para.align,
        Some(Alignment::Left),
        "merged paragraph should have the FOLLOWING paragraph's alignment (left), \
         per §17.13.5.15: the following paragraph's properties win. Got: {:?}",
        merged_para.align
    );
}

// ── Test 2: Reject deleted paragraph mark keeps separate ─────────────────

/// ECMA-376 §17.13.5.15: Rejecting a deleted paragraph mark should keep
/// the two paragraphs separate (undo the deletion).
///
/// Fixture: Same as test 1 — two paragraphs, first has deleted para mark.
///
/// After reject_all:
/// - Should still produce TWO paragraphs
/// - The del marker should be removed (para_mark_status = None)
///
/// Rejecting keeps the deletion undone — the paragraphs remain separate
/// and the del marker is removed.
#[test]
fn spec_reject_deleted_paragraph_mark_keeps_separate() {
    let (_runtime, doc) = import_fixture("para-mark-del-merge");

    // Verify fixture: should start with 2 paragraphs
    let initial_count = top_level_paragraph_count(&doc);
    assert_eq!(
        initial_count, 2,
        "fixture should have 2 paragraphs before reject, got {initial_count}"
    );

    // Reject all tracked changes
    let mut rejected = doc.clone();
    reject_all_with_styles(&mut rejected, None);

    // After rejecting, should still have TWO paragraphs
    let rejected_count = top_level_paragraph_count(&rejected);
    assert_eq!(
        rejected_count, 2,
        "rejecting a deleted paragraph mark should keep two separate paragraphs, got {rejected_count}"
    );

    // The del marker should be removed
    let paras: Vec<_> = rejected
        .blocks
        .iter()
        .filter_map(|tb| match &tb.block {
            BlockNode::Paragraph(p) => Some(p),
            _ => None,
        })
        .collect();
    for (i, p) in paras.iter().enumerate() {
        assert_eq!(
            p.para_mark_status, None,
            "paragraph {} should have para_mark_status=None after reject, got {:?}",
            i, p.para_mark_status
        );
    }

    // Both paragraphs' text should survive
    let text = all_text(&rejected);
    assert!(
        text.contains("First paragraph text"),
        "first paragraph text should survive reject, got: '{text}'"
    );
    assert!(
        text.contains("second paragraph text"),
        "second paragraph text should survive reject, got: '{text}'"
    );
}

// ── Test 3: Accept inserted paragraph mark keeps split ───────────────────

/// ECMA-376 §17.13.5.20: When a paragraph mark is inserted and the insertion
/// is accepted, the split stands — both paragraphs are kept.
///
/// Fixture: Two paragraphs. First has an inserted para mark.
///
/// After accept_all:
/// - Should still have TWO paragraphs
/// - The ins marker should be removed (para_mark_status = None)
#[test]
fn spec_accept_inserted_paragraph_mark_keeps_split() {
    let (_runtime, doc) = import_fixture("para-mark-ins-split");

    // Verify fixture: should start with 2 paragraphs
    let initial_count = top_level_paragraph_count(&doc);
    assert_eq!(
        initial_count, 2,
        "fixture should have 2 paragraphs before accept, got {initial_count}"
    );

    // Verify the first paragraph has an inserted para mark
    let first_para = doc
        .blocks
        .iter()
        .find_map(|tb| match &tb.block {
            BlockNode::Paragraph(p) => Some(p),
            _ => None,
        })
        .expect("should have at least one paragraph");
    assert!(
        matches!(
            &first_para.para_mark_status,
            Some(TrackingStatus::Inserted(_))
        ),
        "first paragraph should have Inserted para_mark_status, got {:?}",
        first_para.para_mark_status
    );

    // Accept all tracked changes
    let mut accepted = doc.clone();
    accept_all(&mut accepted);

    // After accepting, should still have TWO paragraphs (split is preserved)
    let accepted_count = top_level_paragraph_count(&accepted);
    assert_eq!(
        accepted_count, 2,
        "accepting an inserted paragraph mark should keep the split (2 paragraphs), got {accepted_count}"
    );

    // The ins marker should be removed
    let paras: Vec<_> = accepted
        .blocks
        .iter()
        .filter_map(|tb| match &tb.block {
            BlockNode::Paragraph(p) => Some(p),
            _ => None,
        })
        .collect();
    for (i, p) in paras.iter().enumerate() {
        assert_eq!(
            p.para_mark_status, None,
            "paragraph {} should have para_mark_status=None after accept, got {:?}",
            i, p.para_mark_status
        );
    }
}

// ── Test 4: Reject inserted paragraph mark merges back ───────────────────

/// ECMA-376 §17.13.5.20: When a paragraph mark is inserted and the insertion
/// is rejected, the split is undone — paragraphs merge back.
///
/// Fixture: Two paragraphs. First has an inserted para mark.
///
/// After reject_all:
/// - Should produce ONE paragraph (merged back)
///
/// Previously a known gap -- reject_all now correctly merges paragraphs
/// back when an inserted paragraph mark is rejected.
#[test]
fn spec_reject_inserted_paragraph_mark_merges_back() {
    let (_runtime, doc) = import_fixture("para-mark-ins-split");

    // Verify fixture: should start with 2 paragraphs
    let initial_count = top_level_paragraph_count(&doc);
    assert_eq!(
        initial_count, 2,
        "fixture should have 2 paragraphs before reject, got {initial_count}"
    );

    // Reject all tracked changes
    let mut rejected = doc.clone();
    reject_all_with_styles(&mut rejected, None);

    // After rejecting, should merge back into ONE paragraph
    let rejected_count = top_level_paragraph_count(&rejected);
    assert_eq!(
        rejected_count, 1,
        "rejecting an inserted paragraph mark should merge paragraphs back into one, got {rejected_count}"
    );

    // The merged paragraph should contain text from both original paragraphs
    let text = all_text(&rejected);
    assert!(
        text.contains("Before split"),
        "merged paragraph should contain first paragraph's text, got: '{text}'"
    );
    assert!(
        text.contains("after split"),
        "merged paragraph should contain second paragraph's text, got: '{text}'"
    );
}

// ── Test 5: Accept deleted table row removes the row ─────────────────────

/// ECMA-376 §17.13.5.12: A deleted table row should be removed on accept.
///
/// Fixture: Table with 2 rows. Row 1 (index 1) is marked as deleted.
///
/// After accept_all:
/// - Table should have 1 row (the deleted row is removed)
///
/// After reject_all:
/// - Table should have 2 rows (the deleted row is kept, status cleared)
#[test]
fn spec_accept_deleted_table_row_removes_row() {
    let (_runtime, doc) = import_fixture("deleted-table-row");

    // Find the table in the document
    let table = doc
        .blocks
        .iter()
        .find_map(|tb| match &tb.block {
            BlockNode::Table(t) => Some(t),
            _ => None,
        })
        .expect("fixture should contain a table");

    // Verify fixture: table should have 2 rows, second one deleted
    assert_eq!(
        table.rows.len(),
        2,
        "fixture table should have 2 rows, got {}",
        table.rows.len()
    );
    assert!(
        matches!(
            &table.rows[1].tracking_status,
            Some(TrackingStatus::Deleted(_))
        ),
        "row 1 should have Deleted tracking_status, got {:?}",
        table.rows[1].tracking_status
    );

    // Accept all tracked changes
    let mut accepted = doc.clone();
    accept_all(&mut accepted);

    let accepted_table = accepted
        .blocks
        .iter()
        .find_map(|tb| match &tb.block {
            BlockNode::Table(t) => Some(t),
            _ => None,
        })
        .expect("table should still exist after accept (has 1 remaining row)");

    assert_eq!(
        accepted_table.rows.len(),
        1,
        "accepting a deleted table row should remove it, leaving 1 row. Got {}",
        accepted_table.rows.len()
    );

    // The surviving row should be the normal (first) row
    assert_eq!(
        accepted_table.rows[0].tracking_status, None,
        "surviving row should have no tracking status"
    );

    // Verify the surviving row has the expected content
    let cell_text: String = accepted_table.rows[0]
        .cells
        .iter()
        .flat_map(|c| &c.blocks)
        .filter_map(|b| match b {
            BlockNode::Paragraph(p) => {
                let inlines = p.all_inlines_owned();
                Some(
                    inlines
                        .iter()
                        .filter_map(|i| match i {
                            InlineNode::Text(t) => Some(t.text.as_str()),
                            _ => None,
                        })
                        .collect::<Vec<_>>()
                        .join(""),
                )
            }
            _ => None,
        })
        .collect::<Vec<_>>()
        .join(" ");
    assert!(
        cell_text.contains("normal"),
        "surviving row should contain the normal row's text, got: '{cell_text}'"
    );
}

/// Rejecting a deleted table row should keep it (undo the deletion).
#[test]
fn spec_reject_deleted_table_row_keeps_row() {
    let (_runtime, doc) = import_fixture("deleted-table-row");

    let mut rejected = doc.clone();
    reject_all_with_styles(&mut rejected, None);

    let rejected_table = rejected
        .blocks
        .iter()
        .find_map(|tb| match &tb.block {
            BlockNode::Table(t) => Some(t),
            _ => None,
        })
        .expect("table should exist after reject");

    assert_eq!(
        rejected_table.rows.len(),
        2,
        "rejecting a deleted table row should keep both rows, got {}",
        rejected_table.rows.len()
    );

    // Both rows should now have tracking_status = None
    for (i, row) in rejected_table.rows.iter().enumerate() {
        assert_eq!(
            row.tracking_status, None,
            "row {} should have tracking_status=None after reject, got {:?}",
            i, row.tracking_status
        );
    }
}

// ── Test 6: Reject property change restores previous state ───────────────

/// ECMA-376 §17.13.5.29: The child pPr inside pPrChange is the COMPLETE
/// previous state. Rejecting should fully restore it, not partially merge.
///
/// Fixture: Paragraph with current alignment=center, pPrChange containing
/// previous alignment=left.
///
/// After reject_all:
/// - Alignment should be "left" (the previous state), not "center"
///
/// Previously a known gap -- reject_all now correctly restores the previous
/// properties from pPrChange.
#[test]
fn spec_reject_property_change_restores_previous_state() {
    let (_runtime, doc) = import_fixture("ppr-change-reject");

    let paras = common::all_paragraphs(&doc);
    assert!(
        !paras.is_empty(),
        "fixture should have at least one paragraph"
    );

    let p = &paras[0];

    // Verify fixture: current alignment is center
    assert_eq!(
        p.align,
        Some(Alignment::Center),
        "fixture paragraph should have center alignment"
    );

    // Verify fixture: pPrChange records previous alignment as left
    let change = p
        .formatting_change
        .as_ref()
        .expect("paragraph should have formatting_change from pPrChange");
    assert_eq!(
        change.previous_alignment,
        Some(Alignment::Left),
        "pPrChange should record previous alignment as left"
    );

    // Reject all tracked changes
    let mut rejected = doc.clone();
    reject_all_with_styles(&mut rejected, None);

    let rejected_paras = common::all_paragraphs(&rejected);
    assert!(
        !rejected_paras.is_empty(),
        "should have paragraphs after reject"
    );

    let rejected_p = &rejected_paras[0];

    // After reject, alignment should be restored to the previous state (left)
    assert_eq!(
        rejected_p.align,
        Some(Alignment::Left),
        "rejecting pPrChange should restore the previous alignment (left). \
         Per §17.13.5.29, the child pPr inside pPrChange is the COMPLETE \
         previous state that must be fully restored on reject. Got: {:?}",
        rejected_p.align
    );

    // The formatting_change should be cleared after reject
    assert_eq!(
        rejected_p.formatting_change, None,
        "formatting_change should be None after reject (change has been resolved)"
    );
}
